import * as React from 'react';
import { Calendar } from '@tale-ui/react/calendar';
import { parseDate } from '@internationalized/date';

type DateVal = Parameters<NonNullable<React.ComponentProps<typeof Calendar.Root>['onChange']>>[0];

export function DateCalendarPicker() {
  const [value, setValue] = React.useState<DateVal | null>(null);

  return (
    <Calendar.Root
      value={value}
      onChange={setValue}
      defaultValue={parseDate('2026-05-25')}
    >
      <Calendar.Header>
        <Calendar.PreviousButton />
        <Calendar.Heading />
        <Calendar.NextButton />
      </Calendar.Header>
      <Calendar.Grid>
        <Calendar.GridHeader>
          {(day) => <Calendar.GridHeaderCell>{day}</Calendar.GridHeaderCell>}
        </Calendar.GridHeader>
        <Calendar.GridBody>
          {(date) => <Calendar.Cell date={date} />}
        </Calendar.GridBody>
      </Calendar.Grid>
    </Calendar.Root>
  );
}
